INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-814ced5a-moex-00508', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「然而生命也許就是這樣的吧，無論是歡喜或悲傷，總值得我們認認真真的走一趟。我有著這麼多 這麼好的朋友陪我一起走這一條路，你說，我怎麼能不希望這一段路途可以更長更久一點呢？」 根據上文，因為有許多好朋友，才使得生命：', '["值得依戀", "更長更久", "幸福美滿", "多采多姿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00509', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「不知道走哪條路可抵達想去的地方，可能是阿茲海默氏症的早期徵候，原因在於大腦中最先被這 種疾病破壞的區域之一是內嗅皮質，那是我們感知自身位置的關鍵部位。研究人員讓45名有輕度認 知障礙的患者，根據虛擬實境頭盔上所見，找出虛擬的步行路徑。表現最差的受試者，腦脊液中阿 茲海默氏症的生物標記均呈陽性反應。虛擬實境測試或許可成為有效的診斷工具。」 這段文字最適合的標題是：', '["內嗅皮質與阿茲海默氏症的關係", "阿茲海默氏症的典型症狀與治療", "檢測阿茲海默氏症的有效新方法", "虛擬實境與阿茲海默氏症的治療"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00510', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「職場上，開個玩笑、展現幽默，可收人際潤滑，改善工作氛圍之效，但運用不當，反而弄巧成拙。 身為主管，領導才是最重要的任務，而非調笑。朋友間開玩笑，或無傷大雅，但主管跟部屬開玩笑， 未必是幽默。部屬與長官開玩笑更得審慎，因為玩笑是否幽默，決定權向來在對方。如果對方不覺 幽默，那一番好意倒成惡意。即便開自己玩笑，也不一定幽默，很可能因此傷人而不自知。尤其領 導者代表的並非個人，開自己玩笑時，很可能已經傷害了團隊。鼓動幽默時，我們要覺察自己的動 機，注意表現的時機，留心他人的反應。須避免譏諷性與戲弄性的言語，以免傷害他人。幽默固然 有諸多好處，但若自己個性實在不適合，就不必勉強。」 根據上文，下列敘述不符合文意的是：', '["開玩笑得要注意自己身分", "玩笑出於善意則不會傷人", "幽默得搭配適當表達時機", "自嘲也是幽默的一種方式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00511', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「『美』，只在瞬間出現，有時候根本不容人靠近，宛如在雲霧掩擁裡汪洋上的孤絕之島，偶一現 身之後，總讓人懷疑剛才是不是真的見過她。譬如泰姬瑪哈。泰姬瑪哈曾經是我自幼心嚮往之的書 上的圖片，十年前，我終於去了，在那裡度過兩個黃昏然後回來，現在，一切又復歸是書上的圖片。 我只能說：『我去過了。』當然，我也還留著一些細節可以向你描述，譬如那向晚的輪廓模糊的平 原，還有從平原上吹過來的微微有點溫熱的風，粉紅與乳黃相併而成的大理石平台上，有幾朵隨風 落下的白色的素馨花。可是，也就只有這麼多了。而手邊所有的關於歷史的追溯，或者關於工程的 浩大與匠心等等都不過是旁白，是敘述用的資料，一如書上的圖片，只供導引與參考，卻絕不是事 件本身。」 下列選項，何者最符合上文旨意？', '["美感是切身感受，無法複製、保存或轉述", "再美的事物，未能親眼目睹，也僅是過眼雲煙", "旅行不僅提升眼界且增長人生智慧，終歸看山還是山", "在宏偉的歷史遺跡面前，任何文字都難以陳述過往的真實"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00512', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「睡眠並非不清醒。睡眠遠勝於不清醒。夜間的睡眠精緻複雜，充滿活躍的代謝過程，而且有一系 列經過特意安排的獨特階段。腦中有無數功能的修復要仰賴睡眠，且並非單靠其中一種形式的睡眠 就能完成。睡眠的每個階段，包括淺度非快速動眼睡眠、深度非快速動眼睡眠、快速動眼睡眠，在 夜晚的不同時段對腦提供不同好處。因此，沒有某種形式的睡眠比另一種更重要。」 依據上文，最符合文意的選項為：', '["不清醒時與淺度睡眠狀態相似", "夜間的睡眠處於極度平靜狀態", "深度睡眠遠比淺度睡眠更可貴", "適度睡眠可即時修補大腦功能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00513', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「很懷念小時候過年的感覺，有濃濃的趣味，各種糕點食品的味兒，大人難見的笑容，還有一種似 乎可以為所欲為、放鬆壓抑的興奮。人類學家發現，幾乎所有的民族都有自己的慶典。慶典的原始 目的有二：一是敬神祭祖；一是驅邪趕鬼。敬神包括祈福求平安，妻財子祿；驅邪包括治病求健康； 這病，也涵蓋心理及精神上的病。人類各種族的慶典，也有一共同的特色，就是大多都有一套制度 化的儀式，而儀式包括肅穆的典禮和狂放的歌舞酒食。現在過年不如以前來勁，乃是因為聖誕節、 情人節、中秋節等節慶已分批抒發了壓抑。所以，過年原來紓解情緒壓抑的功能就多餘了。」 下列選項，何者最不符合上文所述？', '["逢年過節可以盡情地放鬆壓抑、為所欲為", "慶典的原始目的是：敬神祭祖、驅邪趕鬼", "大多數的民族慶典，都有狂放的歌舞酒食", "多了其他節慶，使現在過年不如以前來勁"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00514', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「資訊時代的到來，網路徹底改變了人類的生活方式。各行各業經網路系統重新佈局，與世界各國 接軌，網路是個新世界，這個世界的人被稱作網民，這個網愈結愈實，愈張愈大，網民以幾何級數 增長。走進電腦網路，可以遨遊世界，談生意，開會討論。教育工作者一樣感受到電腦的便捷，過 去演講，要請專人製幻燈片，不但要等時間，做好也無法修改。如今自己動手用 Powerpoint 做投影 片，方便迅速，還可隨意更換背景以美化畫面。此外，網路資訊豐富，就像一本百科全書，隨時提 供查閱。」 依據上文，全文的主旨為何？', '["網路發展拉近了人類的距離", "網路發展減少人類溝通問題", "網路改變人類的生活和文化", "電子郵件使人們聯繫更便捷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00515', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「我們這兩代，共同照顧農村的新生代，然而，孩子們變成什麼樣子？他們背著很重的書包，在學 校、補習班和家裡三處來回移動；他們鮮少靠近土地、觸摸作物，有空就盯著平板不放、開著電視 節目配晚餐；他們暫時留在鄉下，一上小學或上了國中，就會被帶到都市加入更激烈的求學競爭； 他們踩在田裡就踮腳、沾到泥土就猛拍、看到螞蟻就大叫，也總認為自來水比圳水清澈乾淨。孩子 們生在農村，卻不是在農村活著，他們隨著大人的安排，想盡辦法要離開農村。」 依據上文，作者筆下「農村新生代」離開農村的原因何在？', '["即使是農村，也難逃升學壓力，補習班的影響力深遠", "新生代從小嬌生慣養，家事均由大人代勞，缺乏自我謀生的能力", "在功利主義的社會文化之下，孩子以升學為目標，被抽離土地，缺乏認同", "在電子媒體的時代，如果留在農村，就容易與外界隔絕，沒有辦法跟得上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00516', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「這是一個最尖銳的問題。莫里老人自己回答道：『我當然在受罪。但給予他人，能使我感到自己 還活著。汽車和房子不能給你這種感覺，鏡子裡照出的模樣也不能給你這種感覺。只有當我奉獻出 了時間，當我使那些悲傷的人又露出笑顏，我才感到我仍像以前一樣健康。』這樣，他就道出了生 命的根本意義。」 文中作者所謂的「生命根本意義」是：', '["善用所有時間", "生活無憂無慮", "長保青春歡顏", "樂於幫助他人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00517', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「法國前總理有一次視察某地，手中拎著個超級市場的塑膠袋，接受採訪時，這個袋子也一直拎在 手上，看起來非常自然，並沒有誰覺得他寒酸，沒有誰覺得他不夠紳士，人們反而對他投以欽佩的 目光。」 下列選項，何者最接近法國前總理的表現？', '["節能生活，由自我做起", "為譁眾取寵而特立獨行", "人人平等，並無貴賤之分", "有自信的人不受外界眼光影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
